What does the following program print?

```cpp
#include <random>
#include <iostream>
int main()
{
    std::mt19937 rng{ 0u };
    std::uniform_int_distribution<int> d{ 1, 3 };
    std::cout << d(rng) << ' ';
    std::cout << d(rng) << '\n';
}
```

A student wants to roll a die five times, getting different values each roll. What is wrong with this code?

```cpp
#include <random>
#include <chrono>
#include <iostream>
int main()
{
    for (int i = 0; i < 5; ++i) {
        std::mt19937 rng{ static_cast<unsigned>(
            std::chrono::steady_clock::now()
            .time_since_epoch().count()) };
        std::uniform_int_distribution<int> d{ 1, 6 };
        std::cout << d(rng) << ' ';
    }
}
```

What does this program print?

```cpp
#include <random>
#include <iostream>
int main()
{
    std::mt19937 rng{ 1u };
    std::mt19937 rng2{ 1u };
    std::uniform_int_distribution<int> d{ 0, 9 };
    std::cout << d(rng) << ' ' << d(rng2) << '\n';
}
